# Arguments: jwt_token (str): JWT to be decoded, secret_key (str): Secret key used for encoding the JWT.
# Returns: dict: The payload of the token or an empty dictionary if the token is invalid or cannot be decoded.
# Requires: PyJWT and datetime modules
def cwe_347_0_v1_tool(jwt_token, secret_key):
    import jwt
    from datetime import datetime

    # Initialize an empty dictionary for the claims
    decoded_claims = {}

    try:
        # Decode the JWT using the provided secret key. If successful, store the payload in 'decoded_claims'.
        decoded_claims = jwt.decode(jwt_token, secret_key, algorithms=['HS256'])

        # Check if token is expired
        if 'exp' in decoded_claims:
            expiration_time = datetime.utcfromtimestamp(decoded_claims['exp'])

            if datetime.now() > expiration_time:
                print("The JWT has expired.")
                return {}

    except jwt.exceptions.InvalidTokenError as e:
        # If the token is invalid, print an error message and return an empty dictionary
        print(f"Failed to decode JWT: {e}")

    return decoded_claims

